#!/usr/bin/env bash
# One-click RTL8852BE/RTL8852BS Bluetooth UART9(H5) installer for RK3588S Box V10 Armbian.
# Installs a patched aarch64 rtk_hciattach, systemd service, and verifies hci0.
set -euo pipefail

TTY_DEV="${TTY_DEV:-/dev/ttyS9}"
PROTO="${PROTO:-rtk_h5}"
INIT_SPEED="${INIT_SPEED:-115200}"
INSTALL_BIN="${INSTALL_BIN:-/usr/local/bin/rtk_hciattach}"
RESET_HELPER="${RESET_HELPER:-/usr/local/sbin/rtl8852bs-bt-reset.sh}"
UP_HELPER="${UP_HELPER:-/usr/local/sbin/rtl8852bs-bt-up.sh}"
SERVICE="${SERVICE:-/etc/systemd/system/rtk-hciattach.service}"
EXPECTED_SHA256="f75c297aaf6f1a6e1e76123172a8c695ef84a1bf6816b20cf3b439d74544f3bb"

log() { printf '[rtl8852bs-bt] %s\n' "$*"; }
warn() { printf '[rtl8852bs-bt][WARN] %s\n' "$*" >&2; }
fail() { printf '[rtl8852bs-bt][ERROR] %s\n' "$*" >&2; exit 1; }

need_root() { [ "$(id -u)" -eq 0 ] || fail "请用 root 运行：sudo $0"; }

check_arch() {
  local arch
  arch="$(uname -m)"
  [ "$arch" = "aarch64" ] || fail "当前架构是 $arch；内嵌 rtk_hciattach 是 aarch64 版本。"
}

check_firmware() {
  mkdir -p /lib/firmware/rtlbt /lib/firmware/rtl_bt
  if [ ! -f /lib/firmware/rtlbt/rtl8852bs_fw ] && [ -f /lib/firmware/rtl_bt/rtl8852bs_fw.bin ]; then
    log "补齐 /lib/firmware/rtlbt/rtl8852bs_fw"
    cp -f /lib/firmware/rtl_bt/rtl8852bs_fw.bin /lib/firmware/rtlbt/rtl8852bs_fw
  fi
  if [ ! -f /lib/firmware/rtlbt/rtl8852bs_config ] && [ -f /lib/firmware/rtl_bt/rtl8852bs_config.bin ]; then
    log "补齐 /lib/firmware/rtlbt/rtl8852bs_config"
    cp -f /lib/firmware/rtl_bt/rtl8852bs_config.bin /lib/firmware/rtlbt/rtl8852bs_config
  fi
  [ -f /lib/firmware/rtlbt/rtl8852bs_fw ] || fail "缺少 /lib/firmware/rtlbt/rtl8852bs_fw；请先安装 armbian-firmware 或提供 RTL8852BS BT firmware。"
  [ -f /lib/firmware/rtlbt/rtl8852bs_config ] || fail "缺少 /lib/firmware/rtlbt/rtl8852bs_config；请先安装 armbian-firmware 或提供 RTL8852BS BT config。"
}

install_binary() {
  log "安装 patched rtk_hciattach 到 $INSTALL_BIN"
  install -d -m 0755 "$(dirname "$INSTALL_BIN")"
  local tmp
  tmp="$(mktemp)"
  base64 -d >"$tmp" <<'RTK_HCIATTACH_B64'

RTK_HCIATTACH_B64
  local got
  got="$(sha256sum "$tmp" | awk '{print $1}')"
  [ "$got" = "$EXPECTED_SHA256" ] || fail "内嵌 rtk_hciattach sha256 校验失败：$got != $EXPECTED_SHA256"
  install -m 0755 "$tmp" "$INSTALL_BIN"
  rm -f "$tmp"
}

install_reset_helper() {
  log "安装 BT power reset helper 到 $RESET_HELPER"
  install -d -m 0755 "$(dirname "$RESET_HELPER")"
  cat >"$RESET_HELPER" <<'EOF'
#!/usr/bin/env bash
set -euo pipefail
TTY_DEV="${TTY_DEV:-/dev/ttyS9}"
# 加载 HCI UART/Realtek 相关模块；内建时会自动无害失败。
modprobe hci_uart 2>/dev/null || true
modprobe btrtl 2>/dev/null || true
# fresh boot 或重复重启服务时，先给 BT rfkill 做一次电源复位，避免芯片停在已切波特率/H5 非初始状态。
RFKILL_STATE=""
for d in /sys/class/rfkill/rfkill*; do
  [ -d "$d" ] || continue
  type="$(cat "$d/type" 2>/dev/null || true)"
  name="$(cat "$d/name" 2>/dev/null || true)"
  if [ "$type" = "bluetooth" ] || echo "$name" | grep -qi 'bt\|bluetooth'; then
    RFKILL_STATE="$d/state"
    break
  fi
done
[ -n "$RFKILL_STATE" ] || RFKILL_STATE="/sys/class/rfkill/rfkill0/state"
if [ -w "$RFKILL_STATE" ]; then
  echo 0 >"$RFKILL_STATE" || true
  sleep 0.8
  echo 1 >"$RFKILL_STATE" || true
  sleep 0.8
fi
[ -e "$TTY_DEV" ] || exit 0
EOF
  chmod 0755 "$RESET_HELPER"
}

install_up_helper() {
  log "安装 BT hci0 up helper 到 $UP_HELPER"
  install -d -m 0755 "$(dirname "$UP_HELPER")"
  cat >"$UP_HELPER" <<'EOF'
#!/usr/bin/env bash
set -euo pipefail
if ! command -v hciconfig >/dev/null 2>&1; then
  exit 0
fi
for _ in $(seq 1 20); do
  if [ -e /sys/class/bluetooth/hci0 ]; then
    hciconfig hci0 up 2>/dev/null || true
    hciconfig hci0 2>/dev/null | grep -q 'UP RUNNING' && exit 0
  fi
  sleep 1
done
exit 0
EOF
  chmod 0755 "$UP_HELPER"
}


install_bluez_tools() {
  local missing=0
  for c in btmgmt hciconfig bluetoothctl bluetoothd rfkill; do
    command -v "$c" >/dev/null 2>&1 || missing=1
  done
  if [ "$missing" -eq 0 ]; then
    return 0
  fi
  if command -v apt-get >/dev/null 2>&1; then
    log "安装 BlueZ/rfkill 用户态工具"
    export DEBIAN_FRONTEND=noninteractive
    apt-get update -o Acquire::Retries=2
    apt-get install -y --no-install-recommends bluez rfkill
  else
    warn "缺少 BlueZ/rfkill 工具，且未找到 apt-get；将只配置 HCI attach。"
  fi
}

install_service() {
  log "安装 systemd service 到 $SERVICE"
  local dev_unit="dev-${TTY_DEV#/dev/}.device"
  cat >"$SERVICE" <<EOF
[Unit]
Description=Realtek RTL8852BS Bluetooth H5 attach on UART9
Requires=$dev_unit
After=$dev_unit
Before=bluetooth.service

[Service]
Type=simple
Environment=TTY_DEV=$TTY_DEV
ExecStartPre=$RESET_HELPER
ExecStart=$INSTALL_BIN -n -s $INIT_SPEED $TTY_DEV $PROTO
ExecStartPost=$UP_HELPER
Restart=on-failure
RestartSec=3

[Install]
WantedBy=multi-user.target
EOF
  systemctl daemon-reload
  systemctl enable rtk-hciattach.service >/dev/null
}

start_and_verify() {
  log "启动 rtk-hciattach.service"
  # BlueZ 若先于 UART attach 启动，可能把 controller 留在 DOWN/Busy；先停 bluetoothd，
  # 完成 Realtek H5 firmware attach 并拉起 hci0 后再启动 bluetooth.service。
  systemctl stop bluetooth.service 2>/dev/null || true
  systemctl stop rtk-hciattach.service 2>/dev/null || true
  pkill -f 'rtk_hciattach.*ttyS' 2>/dev/null || true
  systemctl reset-failed rtk-hciattach.service 2>/dev/null || true
  systemctl restart rtk-hciattach.service

  log "等待 hci0 出现并拉起"
  local i ok=0
  for i in $(seq 1 30); do
    sleep 1
    if [ -e /sys/class/bluetooth/hci0 ]; then
      rfkill unblock bluetooth 2>/dev/null || true
      hciconfig hci0 up 2>/dev/null || true
      if hciconfig hci0 2>/dev/null | grep -q 'UP RUNNING'; then
        ok=1
        break
      fi
    fi
  done

  systemctl enable bluetooth.service >/dev/null 2>&1 || true
  systemctl start bluetooth.service 2>/dev/null || true
  sleep 2

  echo '=== rtk-hciattach.service ==='
  systemctl --no-pager --full status rtk-hciattach.service || true
  echo '=== bluetooth.service ==='
  systemctl --no-pager --full status bluetooth.service || true
  echo '=== btmgmt ==='
  btmgmt info 2>&1 || true
  echo '=== hciconfig ==='
  hciconfig -a 2>&1 || true
  echo '=== bluetoothctl ==='
  bluetoothctl show 2>&1 || true
  echo '=== sysfs ==='
  ls -la /sys/class/bluetooth 2>&1 || true

  if [ "$ok" -eq 1 ] && [ -e /sys/class/bluetooth/hci0 ] && hciconfig hci0 2>/dev/null | grep -q 'UP RUNNING'; then
    log "OK：hci0 已出现并 UP RUNNING，RTL8852BS/RTL8852BE Bluetooth UART H5 配置完成。"
  else
    warn "未看到 hci0 UP RUNNING。最近日志如下："
    journalctl -u rtk-hciattach.service --no-pager -n 160 || true
    fail "配置未验证通过。"
  fi
}

verify_only() {
  echo '=== service ==='
  systemctl --no-pager --full status rtk-hciattach.service || true
  echo '=== btmgmt ==='
  btmgmt info 2>&1 || true
  echo '=== hciconfig ==='
  hciconfig -a 2>&1 || true
  echo '=== sysfs ==='
  ls -la /sys/class/bluetooth 2>&1 || true
  [ -e /sys/class/bluetooth/hci0 ] || exit 1
  command -v hciconfig >/dev/null 2>&1 && hciconfig hci0 2>/dev/null | grep -q 'UP RUNNING'
}

uninstall() {
  need_root
  systemctl disable --now rtk-hciattach.service 2>/dev/null || true
  rm -f "$SERVICE" "$RESET_HELPER" "$UP_HELPER"
  systemctl daemon-reload
  log "已删除 service/helper；保留 $INSTALL_BIN，如需删除请手动 rm。"
}

install_all() {
  need_root
  check_arch
  [ -e "$TTY_DEV" ] || fail "找不到 $TTY_DEV；请确认当前镜像 DTB 已启用 UART9。可用 TTY_DEV=/dev/ttySx 覆盖。"
  check_firmware
  install_bluez_tools
  install_binary
  install_reset_helper
  install_up_helper
  install_service
  start_and_verify
}

case "${1:-install}" in
  install) install_all ;;
  verify|status) verify_only ;;
  uninstall) uninstall ;;
  *)
    cat <<EOF
用法：
  sudo $0 [install|verify|status|uninstall]

可覆盖变量：
  TTY_DEV=/dev/ttyS9 INIT_SPEED=115200 PROTO=rtk_h5 sudo -E $0 install
EOF
    exit 2
    ;;
esac
